parameters.jsCode:
// 1. Get the data from previous nodes using  to avoid undefined errors
const workflowData = $node["Get Workflow JSON"].json;
const aiResponse = $node["Diagnose Error"].json.output;
const errorData = $node["On Workflow Error"].json;

// 2. Clone the workflow to avoid mutating original data unexpectedly
let updatedWorkflow = JSON.parse(JSON.stringify(workflowData));

// 3. Safety Check: Ensure the AI actually provided a patch
if (aiResponse && aiResponse.patch && aiResponse.patch.parameterName) {
  const targetNodeName = errorData.execution.lastNodeExecuted;
  const paramToFix = aiResponse.patch.parameterName;
  const newValue = aiResponse.patch.newValue;

  // 4. Loop through nodes and apply the fix
  let found = false;
  for (let node of updatedWorkflow.nodes) {
    if (node.name === targetNodeName) {
      // Initialize parameters if for some reason they don't exist
      node.parameters = node.parameters || {};
      node.parameters[paramToFix] = newValue;

      // Add a note so you can see the fix in the UI
      node.notes = `🛠 AI AUTO-FIX: Changed ${paramToFix} to ${newValue}`;
      found = true;
      break;
    }
  }
}

// 5. Return the result in the standard n8n format
return {
  json: {
    workflowJSON: updatedWorkflow, // This will be used in the PUT body
    diagnosis: aiResponse.diagnosis,
    fixedParam: aiResponse.patch ? aiResponse.patch.parameterName : 'none',
    success: true
  }
};

